// Get the current foreclosure record
const foreclosure = $input.item;
const sbl = foreclosure.fields.SBL;

// Log processing info
console.log(`Processing SBL: ${sbl}`);

// Navigate to the property search page
await $page.goto($node["Configuration"].json.baseURL, { waitUntil: 'networkidle0', timeout: 30000 });

// Click the Public Access button if it exists
try {
  const publicAccessButton = await $page.waitForSelector('a:has-text("Click Here for Public Access")', { timeout: 5000 });
  if (publicAccessButton) {
    console.log('Clicking Public Access button...');
    await publicAccessButton.click();
    await $page.waitForNavigation({ waitUntil: 'networkidle0' });
  }
} catch (error) {
  console.log('No Public Access button found or error clicking it:', error.message);
}

// Check if agreement overlay appears and click "agree" if it does
try {
  const agreeButton = await $page.waitForSelector('input[value="I Agree"]', { timeout: 5000 });
  if (agreeButton) {
    console.log('Clicking agree button...');
    await agreeButton.click();
    await $page.waitForNavigation({ waitUntil: 'networkidle0' });
  }
} catch (error) {
  console.log('No agreement dialog found or error clicking it:', error.message);
}

// Wait for the search form to load
try {
  await $page.waitForSelector('select[name="selectmun"]', { timeout: 10000 });
} catch (error) {
  console.log('Search form not found:', error.message);
  // Take a screenshot to see what went wrong
  const errorScreenshot = await $page.screenshot({ type: 'png', encoding: 'base64' });
  return [
    {
      ...foreclosure,
      error: `Search form not found: ${error.message}`,
      binary: {
        errorScreenshot: {
          data: errorScreenshot,
          mimeType: 'image/png',
          fileName: `error_${sbl}.png`
        }
      }
    }
  ];
}

// Get SBL parts
let sblParts = sbl.split('-');
if (sblParts.length !== 4) {
  return [
    {
      ...foreclosure,
      error: `Invalid SBL format: ${sbl}. Expected format: XXX-X-XX-XXX`
    }
  ];
}

// Select Ulster municipality (106 = Ulster)
try {
  await $page.select('select[name="selectmun"]', '106');
} catch (error) {
  console.log('Error selecting municipality:', error.message);
}

// Fill in SBL parts
await $page.type('input[name="swis"]', sblParts[0]);
await $page.type('input[name="section"]', sblParts[1]);
await $page.type('input[name="block"]', sblParts[2]);
await $page.type('input[name="lot"]', sblParts[3]);

// Click search button
const searchButton = await $page.waitForSelector('input[value="Search"]');
await searchButton.click();

// Wait for results
await $page.waitForNavigation({ waitUntil: 'networkidle0' });

// Check if we have results
const noResultsText = await $page.evaluate(() => {
  const elem = document.querySelector('body');
  return elem ? elem.innerText.includes('No records found') : false;
});

if (noResultsText) {
  return [
    {
      ...foreclosure,
      error: `No property found for SBL: ${sbl}`
    }
  ];
}

// Click on the first result if available
const firstResultLink = await $page.$('a[href*="infopage.jsp"]');
if (!firstResultLink) {
  return [
    {
      ...foreclosure,
      error: `No property link found for SBL: ${sbl}`
    }
  ];
}

await firstResultLink.click();
await $page.waitForNavigation({ waitUntil: 'networkidle0' });

// Extract property information
const propertyInfo = await $page.evaluate(() => {
  const getData = (label) => {
    const labelElement = Array.from(document.querySelectorAll('td')).find(el => el.innerText.includes(label));
    if (labelElement) {
      const valueElement = labelElement.nextElementSibling;
      return valueElement ? valueElement.innerText.trim() : '';
    }
    return '';
  };

  return {
    owner: getData('Primary Owner:'),
    propertyAddress: getData('Location:'),
    propertyClass: getData('Property Class:'),
    assessedValue: getData('Assessed Value:'),
    taxableValue: getData('Taxable Value:'),
    acreage: getData('Acres:'),
    yearBuilt: getData('Year Built:')
  };
});

// Take a screenshot for verification
const screenshot = await $page.screenshot({ type: 'png', encoding: 'base64' });

// Return the enriched foreclosure data
return [
  {
    ...foreclosure,
    propertyInfo,
    binary: {
      screenshot: {
        data: screenshot,
        mimeType: 'image/png',
        fileName: `property_${sbl}.png`
      }
    }
  }
];
